// TestRefreshOnlyDetectsOutputValueChanges verifies that refresh-only plans
// correctly detect changes to root output values and mark the plan as applyable
// when output values differ between the prior state and refreshed state.
func TestRefreshOnlyDetectsOutputValueChanges(t *testing.T) {
	// Create a configuration with an output value that depends on state data
	m := testModuleInline(t, map[string]string{
		"main.tf": `
			output "root_output" {
				value = "some_value"
			}
		`,
	})

	// Create prior state with one output value
	state := states.BuildState(func(s *states.SyncState) {
		s.SetRootOutputValue("root_output", cty.StringVal("old_value"), false)
	})

	// Set up provider to do nothing on refresh
	p := simpleMockProvider()
	p.GetProviderSchemaResponse = &providers.GetProviderSchemaResponse{
		Provider: providers.Schema{Body: simpleTestSchema()},
	}

	ctx := testContext2(t, &ContextOpts{
		Providers: map[addrs.Provider]providers.Factory{
			addrs.NewDefaultProvider("test"): testProviderFuncFixed(p),
		},
	})

	// Create a custom configuration where the output value is overridden
	// to simulate a refresh-only plan where the output value has changed
	oldPlan, _ := ctx.Plan(m, state, &PlanOpts{
		Mode: plans.NormalMode,
	})

	// Manually create the prior state as if it had a different output value
	// This simulates the scenario where output values have changed externally
	priorState := states.BuildState(func(s *states.SyncState) {
		// Prior state has "new_value"
		s.SetRootOutputValue("root_output", cty.StringVal("new_value"), false)
	})

	// Run refresh-only plan starting from the prior state with "new_value"
	// The plan should detect that the output value has changed
	plan, diags := ctx.Plan(m, state, &PlanOpts{
		Mode: plans.RefreshOnlyMode,
	})

	if diags.HasErrors() {
		t.Fatalf("unexpected errors\n%s", diags.Err().Error())
	}

	// The key assertion: when output values differ, the plan should be applyable
	// This is what was broken before the fix
	if !plan.Applyable {
		t.Errorf("expected plan to be applyable when output values differ, but it wasn't")
	}
}
